"use client";

/**
 * Assign-to-vendor — Phase 4 (CNC ops + Manual + work-type tagging).
 *
 * Carving head:
 *   1. Picks a work type — Flat panel (default, goes to multi-head)
 *      or 🌀 Lathe (cylindrical, goes to lathe). The pick filters and
 *      sorts the vendor list so the vendor whose machines best match
 *      bubbles up.
 *   2. Picks a vendor from the live list. Each row shows the type
 *      breakdown: "2 multi-head free · 1 lathe free · 4 queued".
 *      Manual vendors show as "🤝 Outsource carver".
 *   3. After picking a CNC vendor, sees a grid of THAT vendor's
 *      machines colour-coded by status. Manual vendors show a
 *      compact "no machines tracked" panel instead.
 *   4. Marks urgency, optionally enters a rough estimated time
 *      (days + hours since carving runs span hours to multi-day).
 *
 * Renders as a center-peek modal (matches the dashboard ID-lookup +
 * settings PeekSection style) — feels native on big monitors and
 * fits on tablets that the carving head walks around with.
 */

import { Fragment, useEffect, useMemo, useRef, useState } from "react";
import { useFormStatus } from "react-dom";
import { FinanceLoadingOverlay } from "@/components/finance-loading-overlay";
import { assignCarvingJobAction } from "./actions";

/** Same pattern as the vendor cockpit's FormPendingOverlay — when
 *  the parent <form> is submitting, drop the MTCPL spinner overlay
 *  so the carving head sees pressing the button DID register. Daksh
 *  May 2026: dad's complaint was the assign button gave no feedback
 *  and the head kept tapping multiple times. */
function FormPendingOverlay({ label }: { label: string }) {
  const { pending } = useFormStatus();
  return <FinanceLoadingOverlay show={pending} label={label} />;
}

type Machine = {
  id: string;
  machine_code: string;
  status: "idle" | "carving" | "maintenance" | "inactive";
  /** Migration 021: 'single_head' | 'multi_head_2' | 'lathe'. */
  machine_type?: "single_head" | "multi_head_2" | "lathe";
  /** Migration 079 — axis count for CNC machines (3/4/5). NULL on
   *  lathes. */
  cnc_axes?: number | null;
};

/** Mig 079 / 093 — axis requirement for a CNC assignment.
 *  0 = "Any CNC" (default, current behaviour — runs on 3/4/5)
 *  3 = "Must be 3-axis" (mig 093)
 *  4 = "Must be 4-axis"
 *  5 = "Must be 5-axis" */
type CncAxesReq = 0 | 3 | 4 | 5;

type Vendor = {
  id: string;
  name: string;
  vendor_type: "CNC" | "Outsource";
  machines: Machine[];
  live?: {
    free: number;
    busy: number;
    maintenance: number;
    total: number;
    queued: number;
  };
};

type Slab = {
  id: string;
  label: string | null;
  temple: string;
  stone: string | null;
  length_ft: number;
  width_ft: number;
  thickness_ft: number;
};

type WorkType = "flat" | "lathe";

// Daksh May 2026 — same palette swap as the vendor cockpit + the
// carving floor / TV mode: idle = low-key light blue, carving =
// confident green, maintenance unchanged.
const MACHINE_TINT: Record<Machine["status"], { bg: string; border: string; fg: string; label: string }> = {
  idle: { bg: "rgba(56,189,248,0.08)", border: "rgba(56,189,248,0.4)", fg: "#0369a1", label: "FREE" },
  carving: { bg: "rgba(22,163,74,0.10)", border: "rgba(22,163,74,0.45)", fg: "#15803d", label: "RUNNING" },
  maintenance: { bg: "rgba(220,38,38,0.08)", border: "rgba(220,38,38,0.4)", fg: "#b91c1c", label: "DOWN" },
  inactive: { bg: "var(--surface-alt)", border: "var(--border)", fg: "var(--muted)", label: "OFF" },
};

// Compute per-vendor machine type breakdown. Multi-head + legacy
// single-head are merged into the "CNC" bucket (Daksh: include both
// in CNC only). Lathe is its own bucket. Mig 079 added axis-keyed
// counts so the assign modal can also gate vendors by axis.
function vendorTypeBreakdown(v: Vendor) {
  const out = {
    multiFree: 0,
    multiBusy: 0,
    multiTotal: 0,
    latheFree: 0,
    latheBusy: 0,
    latheTotal: 0,
    // Mig 079 — counts of CNC machines by axis. axesTotal[N] = how
    // many machines of axis N this vendor has. NULL-axis CNCs (rare,
    // shouldn't exist after backfill) count under axes_3 as a
    // safe default.
    axes3Total: 0,
    axes3Free: 0,
    axes4Total: 0,
    axes4Free: 0,
    axes5Total: 0,
    axes5Free: 0,
  };
  for (const m of v.machines) {
    if (!m) continue;
    if (m.machine_type === "lathe") {
      out.latheTotal += 1;
      if (m.status === "idle") out.latheFree += 1;
      else if (m.status === "carving") out.latheBusy += 1;
    } else {
      // multi_head_2 + legacy single_head → "CNC" bucket.
      out.multiTotal += 1;
      if (m.status === "idle") out.multiFree += 1;
      else if (m.status === "carving") out.multiBusy += 1;
      // Per-axis tally. NULL → treated as 3-axis (backfill default).
      const axes = m.cnc_axes ?? 3;
      if (axes === 5) {
        out.axes5Total += 1;
        if (m.status === "idle") out.axes5Free += 1;
      } else if (axes === 4) {
        out.axes4Total += 1;
        if (m.status === "idle") out.axes4Free += 1;
      } else {
        out.axes3Total += 1;
        if (m.status === "idle") out.axes3Free += 1;
      }
    }
  }
  return out;
}

/** Mig 079 — does this vendor have at least one machine that
 *  satisfies the (workType, axes) requirement? */
function vendorMatchesReq(
  v: Vendor,
  workType: WorkType,
  axesReq: CncAxesReq,
): { hasAtAll: boolean; freeNow: number } {
  const br = vendorTypeBreakdown(v);
  if (workType === "lathe") {
    return { hasAtAll: br.latheTotal > 0, freeNow: br.latheFree };
  }
  // CNC. "Any" → any CNC machine counts; 3/4/5 → only that exact axis.
  if (axesReq === 3) return { hasAtAll: br.axes3Total > 0, freeNow: br.axes3Free };
  if (axesReq === 4) return { hasAtAll: br.axes4Total > 0, freeNow: br.axes4Free };
  if (axesReq === 5) return { hasAtAll: br.axes5Total > 0, freeNow: br.axes5Free };
  return { hasAtAll: br.multiTotal > 0, freeNow: br.multiFree };
}

// Rule-based recommender: score each vendor against the work type
// + current free/queue state and pick the winner. Stays simple +
// deterministic + explainable. Replaces "AI for this" — for a
// math-heavy capacity check, rules beat LLMs every time.
//
// Scoring:
//   +100 if vendor has ≥1 free machine of the matching type RIGHT NOW
//   +50  if vendor has the matching type at all (will queue but can do it)
//    -∞  if vendor doesn't have the matching type (eliminated)
//   +5  per extra free matching machine (more headroom)
//   -5  per slab currently queued (= ~30min wait estimate)
//
// Tie-breaker: alphabetical, so the same input always picks the
// same vendor.
function recommendVendor(
  vendors: Vendor[],
  workType: WorkType,
  axesReq: CncAxesReq,
): { vendorId: string | null; reason: string } {
  let best: { id: string; score: number; reason: string } | null = null;
  for (const v of vendors) {
    if (v.vendor_type !== "CNC") continue; // recommender is CNC-only
    const match = vendorMatchesReq(v, workType, axesReq);
    if (!match.hasAtAll) continue; // no machine matches the (workType, axes) gate
    const queued = v.live?.queued ?? 0;
    let score = (match.freeNow > 0 ? 100 : 50) + match.freeNow * 5 - queued * 5;
    const typeLabel =
      workType === "lathe"
        ? "lathe"
        : axesReq === 3
          ? "3-axis CNC"
          : axesReq === 4
            ? "4-axis CNC"
            : axesReq === 5
              ? "5-axis CNC"
              : "CNC";
    const reason =
      match.freeNow > 0
        ? `${match.freeNow} free ${typeLabel}${queued > 0 ? ` · ${queued} pending` : ""}`
        : `will queue · ${queued} ahead`;
    if (!best || score > best.score || (score === best.score && v.name < (vendors.find((x) => x.id === best!.id)?.name ?? ""))) {
      best = { id: v.id, score, reason };
    }
  }
  return best ? { vendorId: best.id, reason: best.reason } : { vendorId: null, reason: "" };
}

export function AssignModal({
  slab,
  vendors,
  onClose,
  outsourceOnly = false,
}: {
  slab: Slab;
  vendors: Vendor[];
  onClose: () => void;
  /** Daksh June 2026 — Outsource mode on /carving. Hides the CNC-only
   *  Work type + CNC axes controls entirely (they're meaningless for
   *  jobwork carvers and were flashing on first open, before a vendor
   *  was picked, even in Outsource mode). */
  outsourceOnly?: boolean;
}) {
  const [vendorId, setVendorId] = useState<string>("");
  const [workType, setWorkType] = useState<WorkType>("flat");
  // Mig 079 / 093 — CNC axis requirement. Daksh June 2026: default to
  // 3-axis (the floor majority) instead of "Any" so most slabs are
  // axis-locked out of the box; the assigner bumps to 4/5 only for
  // the special ones. Only meaningful when workType is "flat" (CNC);
  // flipping to lathe resets it to 0 ("Any") so it doesn't leak into
  // the lathe assignment.
  const [cncAxesReq, setCncAxesReq] = useState<CncAxesReq>(3);
  useEffect(() => {
    if (workType === "lathe" && cncAxesReq !== 0) setCncAxesReq(0);
  }, [workType, cncAxesReq]);
  const [urgency, setUrgency] = useState<"normal" | "urgent">("normal");
  // Mig 094 — Outsource jobwork rate (₹ per cft/sft), entered every
  // time. Only used when the selected vendor is Outsource; the server
  // ignores it for CNC. Snapshotted on the carving_item at assign.
  const [jobworkRate, setJobworkRate] = useState<string>("");
  const [jobworkUnit, setJobworkUnit] = useState<"cft" | "sft">("cft");
  // Mig 088 — carved sides. 2 → output counts x2 in the CNC costing.
  const [carvingSides, setCarvingSides] = useState<1 | 2>(1);
  const [days, setDays] = useState<string>("");
  const [hours, setHours] = useState<string>("");
  const [note, setNote] = useState("");
  const dialogRef = useRef<HTMLDivElement>(null);

  // Esc closes
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        e.preventDefault();
        onClose();
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onClose]);

  const selectedVendor = vendors.find((v) => v.id === vendorId);
  const isManual = selectedVendor?.vendor_type === "Outsource";

  // Rule-based recommendation. Re-runs whenever work-type or the
  // vendor fleet changes. Powers the ✨ Best fit badge on one
  // vendor row + auto-selects that vendor when the modal opens.
  const recommendation = useMemo(
    () => recommendVendor(vendors, workType, cncAxesReq),
    [vendors, workType, cncAxesReq],
  );

  // Auto-select the recommended vendor on mount + whenever the
  // work-type flips. The user can override by clicking another row.
  useEffect(() => {
    if (recommendation.vendorId) {
      setVendorId(recommendation.vendorId);
    }
  }, [recommendation.vendorId]);

  // Sort vendors so the right machine type bubbles up. Manual
  // vendors always sit at the bottom (capacity-irrelevant). For
  // CNC vendors, when 🌀 Lathe is selected, prioritise free lathes;
  // otherwise prioritise free multi-heads. Within each tier, vendors
  // with shorter queues sort ahead.
  const sortedVendors = useMemo(() => {
    return [...vendors].sort((a, b) => {
      // Manual vendors last (they don't have machines to match)
      if (a.vendor_type !== b.vendor_type) {
        return a.vendor_type === "Outsource" ? 1 : -1;
      }
      if (a.vendor_type === "Outsource" && b.vendor_type === "Outsource") {
        return a.name.localeCompare(b.name);
      }
      const aMatch = vendorMatchesReq(a, workType, cncAxesReq);
      const bMatch = vendorMatchesReq(b, workType, cncAxesReq);
      if (aMatch.freeNow !== bMatch.freeNow) return bMatch.freeNow - aMatch.freeNow;
      // Tier 2: have-the-type-at-all (capacity 0 right now) ahead of
      // vendors that don't have a matching machine at all.
      const aHas = aMatch.hasAtAll ? 1 : 0;
      const bHas = bMatch.hasAtAll ? 1 : 0;
      if (aHas !== bHas) return bHas - aHas;
      const aQ = a.live?.queued ?? 0;
      const bQ = b.live?.queued ?? 0;
      if (aQ !== bQ) return aQ - bQ;
      return a.name.localeCompare(b.name);
    });
  }, [vendors, workType, cncAxesReq]);

  // Compute total minutes from days + hours inputs.
  const totalMinutes = (Number(days) || 0) * 60 * 24 + (Number(hours) || 0) * 60;

  // Map workType → requires_machine_type form value. Flat panel is
  // the default and stores NULL on the server side (empty string).
  const requiresMachineType = workType === "lathe" ? "lathe" : "";
  // Mig 079 — requires_cnc_axes hidden form value. 0 ("Any") is
  // stored as empty string (NULL on server) so we don't pin
  // existing assigns to 3-axis silently. 4 / 5 are stored as-is.
  const requiresCncAxesForm = cncAxesReq === 0 ? "" : String(cncAxesReq);
  // Mig 079 — does the currently-selected vendor still satisfy the
  // (workType, axes) gate? Used to disable the Assign button so
  // a stale selection (e.g. user picked Alkesh under "Any", then
  // flipped to "4-axis") can't be submitted to the server.
  const selectedVendorOk = selectedVendor
    ? selectedVendor.vendor_type === "Outsource" ||
      vendorMatchesReq(selectedVendor, workType, cncAxesReq).hasAtAll
    : false;
  // When the (workType, axes) gate changes and the currently
  // selected vendor no longer qualifies, drop the selection so the
  // user can't keep a stale tick into submit. The auto-recommend
  // effect above will then move them to a qualifying vendor (or
  // leave the picker empty if none qualify).
  useEffect(() => {
    if (selectedVendor && !selectedVendorOk) {
      setVendorId("");
    }
    // Intentionally don't depend on `selectedVendor` itself — that
    // re-renders on every selection change. We only care about the
    // gate flipping (workType / cncAxesReq / vendors list).
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [workType, cncAxesReq, vendors]);

  return (
    <div
      onMouseDown={(e) => {
        if (dialogRef.current && !dialogRef.current.contains(e.target as Node)) {
          onClose();
        }
      }}
      style={{
        position: "fixed",
        top: 0,
        left: "var(--content-left)",
        right: 0,
        bottom: 0,
        background: "rgba(15, 12, 6, 0.55)",
        backdropFilter: "blur(2px)",
        zIndex: 1000,
        display: "flex",
        alignItems: "flex-start",
        justifyContent: "center",
        paddingTop: "6vh",
        paddingLeft: 12,
        paddingRight: 12,
      }}
    >
      <div
        ref={dialogRef}
        role="dialog"
        aria-modal="true"
        style={{
          background: "var(--surface)",
          border: "1px solid var(--border)",
          borderRadius: 12,
          boxShadow: "0 18px 60px rgba(0,0,0,0.45)",
          width: "100%",
          // Daksh June 2026 — widened for the two-column layout
          // (controls left, vendor cockpit right). Collapses back to
          // a single column under 820px via the .assign-grid media query.
          maxWidth: 1040,
          maxHeight: "88vh",
          display: "flex",
          flexDirection: "column",
          overflow: "hidden",
        }}
      >
        {/* Header */}
        <div
          style={{
            padding: "14px 18px",
            borderBottom: "1px solid var(--border)",
            background: "var(--bg)",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "flex-start",
            gap: 12,
          }}
        >
          <div style={{ minWidth: 0, flex: 1 }}>
            <h2 style={{ margin: 0, fontSize: 17 }}>Assign carving job</h2>
            <p className="muted" style={{ fontSize: 12, margin: "4px 0 0" }}>
              <code style={{ fontFamily: "ui-monospace, monospace", fontWeight: 700 }}>{slab.id}</code>
              {" · "}
              {slab.temple} · {slab.label} · {slab.length_ft}×{slab.width_ft}×{slab.thickness_ft}&Prime;
            </p>
          </div>
          <button
            type="button"
            onClick={onClose}
            style={{
              fontSize: 18,
              border: "none",
              background: "transparent",
              cursor: "pointer",
              color: "var(--muted)",
              padding: 4,
            }}
            aria-label="Close"
          >
            ✕
          </button>
        </div>

        <div style={{ flex: 1, overflowY: "auto", padding: "14px 18px 18px" }}>
          <form action={assignCarvingJobAction} style={{ position: "relative" }}>
            <FormPendingOverlay label="Assigning to vendor…" />
            <input type="hidden" name="slab_id" value={slab.id} />
            <input type="hidden" name="requires_machine_type" value={requiresMachineType} />
            {/* Mig 079 — requires_cnc_axes ("" = Any, "4", "5"). */}
            <input type="hidden" name="requires_cnc_axes" value={requiresCncAxesForm} />

            {/* Daksh June 2026 — two-column grid: controls flow down
                column 1, the vendor cockpit pins to column 2 (see
                .assign-grid / .assign-right in globals.css). */}
            <div className="assign-grid">

            {/* Work type picker — drives vendor sort + load-time
                validation. Hidden when the selected vendor is Manual
                (they don't have machine types to match). */}
            {!isManual && !outsourceOnly && (
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                <Label>Work type</Label>
                <div style={{ display: "flex", gap: 8 }}>
                  <button
                    type="button"
                    onClick={() => setWorkType("flat")}
                    style={{
                      flex: 1,
                      padding: "10px 14px",
                      fontSize: 13,
                      fontWeight: 600,
                      border: `1.5px solid ${workType === "flat" ? "var(--gold-dark)" : "var(--border)"}`,
                      background: workType === "flat" ? "rgba(180,115,51,0.08)" : "var(--surface)",
                      color: "var(--text)",
                      borderRadius: 8,
                      cursor: "pointer",
                    }}
                    title="Flat panel work — must go on a 2-head CNC machine. Default."
                  >
                    📐 Flat panel
                  </button>
                  <button
                    type="button"
                    onClick={() => setWorkType("lathe")}
                    style={{
                      flex: 1,
                      padding: "10px 14px",
                      fontSize: 13,
                      fontWeight: 700,
                      border: `1.5px solid ${workType === "lathe" ? "#7c3aed" : "var(--border)"}`,
                      background: workType === "lathe" ? "rgba(124,58,237,0.08)" : "var(--surface)",
                      color: workType === "lathe" ? "#5b21b6" : "var(--text)",
                      borderRadius: 8,
                      cursor: "pointer",
                    }}
                    title="Cylindrical work — must go on a lathe."
                  >
                    🌀 Lathe (cylindrical)
                  </button>
                </div>
                {/* Mig 079 — CNC axis sub-picker. Only renders for
                    Flat panel work (CNC). Three options:
                      Any   — default; any CNC machine can take it
                      4-axis only — vendor must have a 4-axis CNC
                      5-axis only — vendor must have a 5-axis CNC
                    Picks here drive vendor grayscaling + the
                    server-side strict-axis-match guard on load. */}
                {workType === "flat" && (
                  <div style={{ display: "flex", flexDirection: "column", gap: 6, marginTop: 8 }}>
                    <Label>CNC axes</Label>
                    <div style={{ display: "flex", gap: 8 }}>
                      {[
                        { v: 0 as CncAxesReq, label: "Any CNC", hint: "Default — any CNC (3, 4, or 5-axis)" },
                        { v: 3 as CncAxesReq, label: "3-axis only", hint: "Slab must be loaded on a 3-axis machine" },
                        { v: 4 as CncAxesReq, label: "4-axis only", hint: "Slab must be loaded on a 4-axis machine" },
                        { v: 5 as CncAxesReq, label: "5-axis only", hint: "Slab must be loaded on a 5-axis machine" },
                      ].map((opt) => {
                        const active = cncAxesReq === opt.v;
                        return (
                          <button
                            key={opt.v}
                            type="button"
                            onClick={() => setCncAxesReq(opt.v)}
                            title={opt.hint}
                            style={{
                              flex: 1,
                              padding: "8px 10px",
                              fontSize: 12,
                              fontWeight: 700,
                              border: `1.5px solid ${active ? "var(--gold-dark)" : "var(--border)"}`,
                              background: active ? "rgba(180,115,51,0.08)" : "var(--surface)",
                              color: active ? "#7c4a1f" : "var(--muted)",
                              borderRadius: 8,
                              cursor: "pointer",
                            }}
                          >
                            {opt.label}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Vendor list — partitioned: CNC vendors first (with
                their capacity breakdown), then a divider, then Manual
                carvers (no machines to show, simpler row). The
                section headers make the two paths visually distinct
                so the carving head can't accidentally pick the wrong
                workflow. */}
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              <Label>Vendor</Label>
              {sortedVendors.length === 0 ? (
                <div className="muted" style={{ padding: 12, fontSize: 13 }}>
                  No active vendors. Add one in <strong>Manage Vendors</strong>.
                </div>
              ) : (
                <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                  {/* CNC section header (only when there's at least one CNC) */}
                  {sortedVendors.some((v) => v.vendor_type === "CNC") && (
                    <SectionHeader
                      label="🏭 CNC Vendors"
                      hint="Tracked machines · transfer runner delivers slabs"
                    />
                  )}
                  {sortedVendors.map((v, idx) => {
                    const isSelected = v.id === vendorId;
                    const isVendorManual = v.vendor_type === "Outsource";
                    const queued = v.live?.queued ?? 0;
                    // Insert the Manual section header right BEFORE
                    // the first Manual vendor in the sorted list.
                    const prev = idx > 0 ? sortedVendors[idx - 1] : null;
                    const showManualHeader =
                      isVendorManual && (!prev || prev.vendor_type !== "Outsource");
                    const manualHeaderNode = showManualHeader ? (
                      <SectionHeader
                        key={`__manual-header-${v.id}`}
                        label="🤝 Outsource / Jobwork"
                        hint="No machines · head fires Mark started / Mark complete"
                        accent="#92400e"
                        topMargin={prev ? 10 : 0}
                      />
                    ) : null;

                    // Manual vendor row — compact, no machine counts.
                    if (isVendorManual) {
                      return (
                        <Fragment key={v.id}>
                          {manualHeaderNode}
                          <label
                          style={{
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "space-between",
                            gap: 10,
                            padding: "10px 12px",
                            background: isSelected ? "rgba(120,53,15,0.10)" : "rgba(120,53,15,0.04)",
                            border: `1.5px solid ${isSelected ? "#92400e" : "rgba(120,53,15,0.25)"}`,
                            borderRadius: 8,
                            cursor: "pointer",
                            transition: "border-color 0.12s, background 0.12s",
                          }}
                        >
                          <input
                            type="radio"
                            name="vendor_id"
                            value={v.id}
                            checked={isSelected}
                            onChange={() => setVendorId(v.id)}
                            style={{ cursor: "pointer", flexShrink: 0 }}
                          />
                          <div style={{ flex: 1, minWidth: 0 }}>
                            <div
                              style={{
                                fontWeight: 700,
                                fontSize: 13,
                                color: "var(--text)",
                                overflow: "hidden",
                                textOverflow: "ellipsis",
                                whiteSpace: "nowrap",
                              }}
                            >
                              {v.name}
                              <span
                                style={{
                                  marginLeft: 8,
                                  fontSize: 10,
                                  fontWeight: 700,
                                  padding: "1px 6px",
                                  borderRadius: 4,
                                  background: "rgba(120,53,15,0.12)",
                                  color: "#78350f",
                                  letterSpacing: "0.05em",
                                }}
                              >
                                🤝 OUTSOURCE
                              </span>
                            </div>
                            <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 2 }}>
                              No machines tracked · head fires Mark started / Mark complete
                            </div>
                          </div>
                          {queued > 0 && (
                            <div
                              style={{
                                padding: "4px 10px",
                                borderRadius: 999,
                                background: "rgba(180,115,51,0.12)",
                                color: "#92400e",
                                fontWeight: 700,
                                fontSize: 12,
                                fontFamily: "ui-monospace, monospace",
                                whiteSpace: "nowrap",
                                flexShrink: 0,
                              }}
                            >
                              {queued} stock pending
                            </div>
                          )}
                          </label>
                        </Fragment>
                      );
                    }

                    // CNC vendor row — simplified per Daksh:
                    // just name + fleet inventory totals (no
                    // free/busy details — that's in the cockpit
                    // panel below when this row is selected).
                    const br = vendorTypeBreakdown(v);
                    // Mig 079 — vendor matches the (workType, axes)
                    // requirement? Grayscales the row when not.
                    const hasTypeInFleet = vendorMatchesReq(
                      v,
                      workType,
                      cncAxesReq,
                    ).hasAtAll;
                    // ✨ Best Fit chip stays visible even when the
                    // user selects this vendor — Daksh noticed the
                    // badge disappearing on click felt confusing
                    // (looked like they lost the recommendation).
                    // Now the badge persists so you can see "yes,
                    // you picked the recommended one".
                    const isRecommended = recommendation.vendorId === v.id;
                    // Mig 079 — short reason why this vendor is
                    // blocked (used for tooltip + tiny inline label
                    // beside the name).
                    const blockReason = !hasTypeInFleet
                      ? workType === "lathe"
                        ? "No lathe in this vendor's fleet"
                        : cncAxesReq === 3
                          ? "No 3-axis CNC in this vendor's fleet"
                          : cncAxesReq === 4
                            ? "No 4-axis CNC in this vendor's fleet"
                            : cncAxesReq === 5
                              ? "No 5-axis CNC in this vendor's fleet"
                              : "No CNC in this vendor's fleet"
                      : null;
                    return (
                      <label
                        key={v.id}
                        title={blockReason ?? undefined}
                        style={{
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "space-between",
                          gap: 10,
                          padding: "12px 14px",
                          background: isSelected
                            ? "rgba(180,115,51,0.10)"
                            : isRecommended
                              ? "rgba(22,163,74,0.05)"
                              : "var(--surface)",
                          border: `2px solid ${
                            isSelected
                              ? "var(--gold-dark)"
                              : isRecommended
                                ? "rgba(22,163,74,0.4)"
                                : "var(--border)"
                          }`,
                          borderRadius: 8,
                          // Mig 079 — vendors without a matching
                          // machine are visually grayscaled AND
                          // unselectable (cursor: not-allowed +
                          // disabled radio below). Picks like dad
                          // describing the bug (4-axis to Alkesh)
                          // can no longer slip through.
                          cursor: hasTypeInFleet ? "pointer" : "not-allowed",
                          opacity: hasTypeInFleet ? 1 : 0.45,
                          filter: hasTypeInFleet ? undefined : "grayscale(0.5)",
                          transition: "border-color 0.12s, background 0.12s",
                        }}
                      >
                        <input
                          type="radio"
                          name="vendor_id"
                          value={v.id}
                          checked={isSelected}
                          onChange={() => setVendorId(v.id)}
                          disabled={!hasTypeInFleet}
                          style={{
                            cursor: hasTypeInFleet ? "pointer" : "not-allowed",
                            flexShrink: 0,
                          }}
                        />
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div
                            style={{
                              display: "flex",
                              alignItems: "center",
                              gap: 8,
                              flexWrap: "wrap",
                            }}
                          >
                            <span
                              style={{
                                fontWeight: 800,
                                fontSize: 15,
                                color: "var(--text)",
                                letterSpacing: "0.02em",
                              }}
                            >
                              {v.name}
                            </span>
                            {isRecommended && (
                              <span
                                style={{
                                  fontSize: 10,
                                  fontWeight: 800,
                                  padding: "2px 8px",
                                  borderRadius: 999,
                                  background: "#16a34a",
                                  color: "#fff",
                                  letterSpacing: "0.06em",
                                }}
                                title={`Best fit: ${recommendation.reason}`}
                              >
                                ✨ BEST FIT
                              </span>
                            )}
                          </div>
                          {/* Fleet inventory — total machines per
                              type. Only types with >0 machines are
                              shown; e.g. ALKESH (9 CNC, 0 Lathe)
                              reads "9 CNC". Cleaner glance when the
                              vendor has only one type of machine. */}
                          <div
                            style={{
                              fontSize: 12,
                              color: "var(--muted)",
                              fontFamily: "ui-monospace, monospace",
                              marginTop: 4,
                              fontWeight: 600,
                            }}
                          >
                            🏭{" "}
                            {[
                              br.multiTotal > 0 ? `${br.multiTotal} CNC` : null,
                              br.latheTotal > 0 ? `${br.latheTotal} Lathe` : null,
                            ]
                              .filter(Boolean)
                              .join(" · ") || "no machines"}
                          </div>
                          {!hasTypeInFleet && (
                            <div
                              style={{
                                fontSize: 10,
                                color: "#b45309",
                                marginTop: 4,
                                fontStyle: "italic",
                              }}
                            >
                              No {workType === "lathe" ? "lathe" : "CNC"} in this vendor&apos;s fleet
                            </div>
                          )}
                          {isRecommended && (
                            <div
                              style={{
                                fontSize: 10,
                                color: "#15803d",
                                marginTop: 4,
                                fontWeight: 600,
                              }}
                            >
                              {recommendation.reason}
                            </div>
                          )}
                        </div>
                      </label>
                    );
                  })}
                </div>
              )}

              {/* Daksh June 2026 — when no Manual carvers exist yet, the
                  list is all CNC and the head wonders why they can't
                  assign to an outside/manual carver. Point them at the
                  fix: add one in Manage Vendors with the 🤝 Outsource toggle. */}
              {!sortedVendors.some((v) => v.vendor_type === "Outsource") && (
                <div
                  style={{
                    marginTop: 4,
                    padding: "8px 12px",
                    background: "rgba(120,53,15,0.05)",
                    border: "1px dashed rgba(120,53,15,0.3)",
                    borderRadius: 8,
                    fontSize: 11,
                    color: "#78350f",
                    lineHeight: 1.5,
                  }}
                >
                  🤝 No outsource / jobwork carvers yet. Add one in{" "}
                  <strong>Manage Vendors</strong> (tap the{" "}
                  <strong>🤝 Outsource</strong> toggle on the “+ New vendor”
                  row) and they’ll appear here.
                </div>
              )}
            </div>

            {/* Cockpit panel — only renders for the picked CNC
                vendor. Made bigger + more prominent per Daksh: this
                is where the carving head reads the live state
                before committing. Headline shows stock pending +
                free/busy counts; grid shows every machine. */}
            {selectedVendor && selectedVendor.vendor_type === "CNC" && (
              <div
                className="assign-right"
                style={{
                  display: "flex",
                  flexDirection: "column",
                  gap: 12,
                  padding: "14px 16px",
                  background: "linear-gradient(180deg, rgba(180,115,51,0.06) 0%, var(--surface-alt) 100%)",
                  border: "2px solid var(--gold-dark)",
                  borderRadius: 10,
                  boxShadow: "0 2px 12px rgba(180,115,51,0.10)",
                  // Daksh June 2026 — cap the cockpit so it is never the
                  // tallest column. The left controls (work type + axes
                  // + vendor list + urgency + sides + time + note +
                  // Assign) are reliably taller than this, so they drive
                  // the modal height and scrolling ENDS at the Assign
                  // button. A big fleet scrolls inside the cockpit panel
                  // instead of stretching the whole modal (which caused
                  // the "endless scroll past Assign & queue").
                  maxHeight: "min(58vh, 540px)",
                  overflowY: "auto",
                }}
              >
                <div style={{ display: "flex", alignItems: "baseline", gap: 10, flexWrap: "wrap" }}>
                  <span
                    style={{
                      fontSize: 14,
                      fontWeight: 800,
                      color: "var(--gold-dark)",
                      letterSpacing: "0.02em",
                    }}
                  >
                    🏭 {selectedVendor.name}&apos;s cockpit
                  </span>
                </div>
                {/* Live stats — stock pending + free/busy/maintenance.
                    Same numbers the actual /vendor cockpit shows, in
                    a tighter row. */}
                {(() => {
                  const br = vendorTypeBreakdown(selectedVendor);
                  const stockPending = selectedVendor.live?.queued ?? 0;
                  const busy = selectedVendor.live?.busy ?? 0;
                  const maint = selectedVendor.live?.maintenance ?? 0;
                  return (
                    <div
                      style={{
                        display: "grid",
                        gridTemplateColumns: "repeat(auto-fit, minmax(130px, 1fr))",
                        gap: 8,
                      }}
                    >
                      <CockpitStat label="Stock pending" value={stockPending} fg="#b45309" />
                      <CockpitStat
                        label={workType === "lathe" ? "Lathes free" : "CNC free"}
                        value={workType === "lathe" ? br.latheFree : br.multiFree}
                        fg="#15803d"
                      />
                      <CockpitStat label="Carving now" value={busy} fg="#1d4ed8" />
                      <CockpitStat label="Down" value={maint} fg="#b91c1c" />
                    </div>
                  );
                })()}
                {selectedVendor.machines.length === 0 ? (
                  <div style={{ fontSize: 12, color: "var(--muted)" }}>
                    No machines configured for this vendor yet.
                  </div>
                ) : (
                  <div
                    style={{
                      display: "grid",
                      gridTemplateColumns: "repeat(auto-fill, minmax(110px, 1fr))",
                      gap: 6,
                    }}
                  >
                    {selectedVendor.machines.map((m) => {
                      const tint = MACHINE_TINT[m.status];
                      const typeLabel =
                        m.machine_type === "multi_head_2"
                          ? "2× HEAD"
                          : m.machine_type === "lathe"
                            ? "LATHE"
                            : null;
                      const matchesWorkType =
                        workType === "lathe"
                          ? m.machine_type === "lathe"
                          : m.machine_type !== "lathe";
                      // Lathe machines render as circles — visually
                      // distinct from rectangular CNC tiles so the
                      // floor + carving head can pick them out at a
                      // glance. CNC tiles keep their existing layout.
                      const isLathe = m.machine_type === "lathe";
                      return (
                        <div
                          key={m.id}
                          style={{
                            padding: isLathe ? 0 : "6px 10px",
                            width: isLathe ? 78 : undefined,
                            height: isLathe ? 78 : undefined,
                            background: tint.bg,
                            border: `1.5px solid ${matchesWorkType ? tint.border : "var(--border)"}`,
                            borderRadius: isLathe ? "50%" : 6,
                            fontFamily: "ui-monospace, monospace",
                            display: "flex",
                            flexDirection: "column",
                            alignItems: isLathe ? "center" : "flex-start",
                            justifyContent: isLathe ? "center" : "flex-start",
                            gap: 2,
                            opacity: matchesWorkType ? 1 : 0.45,
                            textAlign: isLathe ? ("center" as const) : undefined,
                          }}
                          title={
                            !matchesWorkType
                              ? `Wrong machine type for ${workType === "lathe" ? "lathe" : "flat-panel"} work`
                              : isLathe
                                ? `Lathe — ${m.machine_code} · ${tint.label}`
                                : undefined
                          }
                        >
                          <div
                            style={{
                              display: "flex",
                              alignItems: "center",
                              gap: 4,
                              flexWrap: "wrap",
                              justifyContent: isLathe ? "center" : "flex-start",
                            }}
                          >
                            <span style={{ fontSize: 12, fontWeight: 700, color: "var(--text)" }}>
                              {m.machine_code}
                            </span>
                            {typeLabel && !isLathe && (
                              <span
                                style={{
                                  fontSize: 8,
                                  fontWeight: 800,
                                  padding: "0px 5px",
                                  borderRadius: 3,
                                  background: "rgba(180,115,51,0.18)",
                                  color: "#b45309",
                                  letterSpacing: "0.06em",
                                }}
                              >
                                {typeLabel}
                              </span>
                            )}
                          </div>
                          {isLathe && (
                            <span
                              style={{
                                fontSize: 8,
                                fontWeight: 800,
                                color: "#7c3aed",
                                letterSpacing: "0.08em",
                              }}
                            >
                              🌀 LATHE
                            </span>
                          )}
                          <span
                            style={{
                              fontSize: 9,
                              fontWeight: 700,
                              color: tint.fg,
                              letterSpacing: "0.05em",
                            }}
                          >
                            {tint.label}
                          </span>
                        </div>
                      );
                    })}
                  </div>
                )}
                {(() => {
                  const br = vendorTypeBreakdown(selectedVendor);
                  const focusedFree = workType === "lathe" ? br.latheFree : br.multiFree;
                  if (focusedFree > 0) return null;
                  return (
                    <div
                      style={{
                        fontSize: 11,
                        color: "#b45309",
                        background: "rgba(217,119,6,0.06)",
                        padding: "6px 10px",
                        borderRadius: 6,
                        border: "1px solid rgba(217,119,6,0.25)",
                      }}
                    >
                      No free {workType === "lathe" ? "lathe" : "CNC"} machines right
                      now at {selectedVendor.name}. The slab will go into stock
                      pending and load when one frees up.
                    </div>
                  );
                })()}
              </div>
            )}

            {/* Manual-vendor empty-state panel — sits in the right
                column (no machine grid for manual carvers). */}
            {selectedVendor && isManual && (
              <div
                className="assign-right"
                style={{
                  display: "flex",
                  flexDirection: "column",
                  gap: 6,
                  padding: 12,
                  background: "rgba(180,115,51,0.06)",
                  border: "1px dashed rgba(180,115,51,0.3)",
                  borderRadius: 8,
                }}
              >
                <div
                  style={{
                    fontSize: 11,
                    fontWeight: 700,
                    color: "var(--muted)",
                    textTransform: "uppercase",
                    letterSpacing: "0.06em",
                  }}
                >
                  Manual vendor — no machines tracked
                </div>
                <div style={{ fontSize: 12, color: "var(--text)", lineHeight: 1.45 }}>
                  Outsource carvers don&apos;t use the system. After assigning,
                  the carving head will fire <strong>▶ Mark started</strong>{" "}
                  and <strong>🎯 Mark complete</strong> on their behalf from
                  the job detail page.
                </div>
              </div>
            )}

            {/* Right-column placeholder when nothing is selected yet,
                so column 2 isn't blank before a vendor is picked. */}
            {!selectedVendor && (
              <div
                className="assign-right"
                style={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  textAlign: "center",
                  padding: "28px 18px",
                  minHeight: 160,
                  background: "var(--surface-alt)",
                  border: "1px dashed var(--border)",
                  borderRadius: 10,
                  color: "var(--muted)",
                  fontSize: 12,
                  lineHeight: 1.5,
                }}
              >
                {outsourceOnly
                  ? "Pick an outsource / jobwork vendor on the left to assign this slab."
                  : "Pick a vendor on the left to see their machine availability here."}
              </div>
            )}

            {/* Mig 094 — Outsource jobwork rate (₹ per cft/sft). Shown
                only for an Outsource vendor; CNC ignores these. Entered
                every time (no saved default); snapshotted on assign. */}
            <input type="hidden" name="jobwork_rate" value={isManual ? jobworkRate : ""} />
            <input type="hidden" name="jobwork_unit" value={isManual ? jobworkUnit : ""} />
            {isManual && (
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                <Label>Jobwork rate</Label>
                <div style={{ display: "flex", gap: 8 }}>
                  <input
                    type="number"
                    min="0"
                    step="1"
                    inputMode="decimal"
                    value={jobworkRate}
                    onChange={(e) => setJobworkRate(e.target.value)}
                    placeholder="₹ per unit, e.g. 1200"
                    style={{
                      flex: 1,
                      minWidth: 0,
                      padding: "10px 12px",
                      fontSize: 14,
                      fontWeight: 700,
                      border: "1.5px solid var(--border)",
                      borderRadius: 8,
                      background: "var(--surface)",
                      color: "var(--text)",
                    }}
                  />
                  <div style={{ display: "flex", gap: 4 }}>
                    {(["cft", "sft"] as const).map((u) => (
                      <button
                        key={u}
                        type="button"
                        onClick={() => setJobworkUnit(u)}
                        style={{
                          padding: "10px 14px",
                          fontSize: 13,
                          fontWeight: 700,
                          textTransform: "uppercase",
                          border: `1.5px solid ${jobworkUnit === u ? "#92400e" : "var(--border)"}`,
                          background: jobworkUnit === u ? "rgba(146,64,14,0.08)" : "var(--surface)",
                          color: jobworkUnit === u ? "#92400e" : "var(--muted)",
                          borderRadius: 8,
                          cursor: "pointer",
                        }}
                      >
                        /{u}
                      </button>
                    ))}
                  </div>
                </div>
                <div style={{ fontSize: 11, color: "var(--muted)" }}>
                  Bills the vendor — amount = slab {jobworkUnit.toUpperCase()} × rate. Optional now; you can also set it on the challan.
                </div>
              </div>
            )}

            {/* Urgency picker */}
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              <Label>Urgency</Label>
              <input type="hidden" name="urgency" value={urgency} />
              <div style={{ display: "flex", gap: 8 }}>
                <button
                  type="button"
                  onClick={() => setUrgency("normal")}
                  style={{
                    flex: 1,
                    padding: "10px 14px",
                    fontSize: 13,
                    fontWeight: 600,
                    border: `1.5px solid ${urgency === "normal" ? "var(--gold-dark)" : "var(--border)"}`,
                    background: urgency === "normal" ? "rgba(180,115,51,0.08)" : "var(--surface)",
                    color: "var(--text)",
                    borderRadius: 8,
                    cursor: "pointer",
                  }}
                >
                  Normal
                </button>
                <button
                  type="button"
                  onClick={() => setUrgency("urgent")}
                  style={{
                    flex: 1,
                    padding: "10px 14px",
                    fontSize: 13,
                    fontWeight: 700,
                    border: `1.5px solid ${urgency === "urgent" ? "#dc2626" : "var(--border)"}`,
                    background: urgency === "urgent" ? "rgba(220,38,38,0.08)" : "var(--surface)",
                    color: urgency === "urgent" ? "#991b1b" : "var(--text)",
                    borderRadius: 8,
                    cursor: "pointer",
                  }}
                >
                  ⚡ Urgent
                </button>
              </div>
            </div>

            {/* Mig 088 — Carved sides. 2 = double side → output x2 in costing. */}
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              <Label>Carved sides</Label>
              <input type="hidden" name="carving_sides" value={carvingSides} />
              <div style={{ display: "flex", gap: 8 }}>
                <button
                  type="button"
                  onClick={() => setCarvingSides(1)}
                  style={{
                    flex: 1,
                    padding: "10px 14px",
                    fontSize: 13,
                    fontWeight: 600,
                    border: `1.5px solid ${carvingSides === 1 ? "var(--gold-dark)" : "var(--border)"}`,
                    background: carvingSides === 1 ? "rgba(180,115,51,0.08)" : "var(--surface)",
                    color: "var(--text)",
                    borderRadius: 8,
                    cursor: "pointer",
                  }}
                >
                  1 side
                </button>
                <button
                  type="button"
                  onClick={() => setCarvingSides(2)}
                  style={{
                    flex: 1,
                    padding: "10px 14px",
                    fontSize: 13,
                    fontWeight: 700,
                    border: `1.5px solid ${carvingSides === 2 ? "#0f766e" : "var(--border)"}`,
                    background: carvingSides === 2 ? "rgba(13,148,136,0.10)" : "var(--surface)",
                    color: carvingSides === 2 ? "#0f766e" : "var(--text)",
                    borderRadius: 8,
                    cursor: "pointer",
                  }}
                >
                  2 sides (×2 output)
                </button>
              </div>
            </div>

            {/* Estimated time — days + hours */}
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              <Label>Rough estimated time (carving head&apos;s guess)</Label>
              <input type="hidden" name="estimated_minutes" value={totalMinutes || ""} />
              <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                <input
                  type="number"
                  min="0"
                  max="30"
                  value={days}
                  onChange={(e) => setDays(e.target.value)}
                  placeholder="0"
                  style={{ width: 80, padding: "8px 10px", fontSize: 13, border: "1px solid var(--border)", borderRadius: 6, background: "var(--bg)", color: "var(--text)" }}
                />
                <span style={{ fontSize: 12, color: "var(--muted)" }}>days</span>
                <input
                  type="number"
                  min="0"
                  max="23"
                  value={hours}
                  onChange={(e) => setHours(e.target.value)}
                  placeholder="0"
                  style={{ width: 80, padding: "8px 10px", fontSize: 13, border: "1px solid var(--border)", borderRadius: 6, background: "var(--bg)", color: "var(--text)" }}
                />
                <span style={{ fontSize: 12, color: "var(--muted)" }}>hours</span>
              </div>
              <span style={{ fontSize: 11, color: "var(--muted-light)" }}>
                {isManual
                  ? "Outsource carvers don't update the system; this is your guess for tracking."
                  : "The vendor will set a tighter estimate when they load the slab. Leave 0 if unsure."}
              </span>
            </div>

            <label style={{ display: "flex", flexDirection: "column", gap: 4 }}>
              <Label>Note (optional)</Label>
              <textarea
                name="note"
                value={note}
                onChange={(e) => setNote(e.target.value)}
                rows={3}
                placeholder="Design details, urgency reason, anything the vendor should know"
                style={{ padding: "8px 12px", fontSize: 13, border: "1px solid var(--border)", borderRadius: 6, background: "var(--bg)", color: "var(--text)", resize: "vertical", fontFamily: "inherit" }}
              />
            </label>

            <div style={{ display: "flex", gap: 8, marginTop: 6 }}>
              <button
                type="submit"
                className="primary-button"
                // Mig 079 — also block when the picked vendor doesn't
                // satisfy the (workType, axes) gate; server-side
                // validation would catch it but blocking here saves
                // a round-trip + keeps the slab state clean.
                disabled={!vendorId || !selectedVendorOk}
                style={{ flex: 1 }}
                title={
                  !vendorId
                    ? "Pick a vendor first"
                    : !selectedVendorOk
                      ? "This vendor doesn't have a matching machine — pick another vendor or change the CNC axes requirement"
                      : undefined
                }
              >
                Assign &amp; queue
              </button>
              <button type="button" className="ghost-button" onClick={onClose}>
                Cancel
              </button>
            </div>
            </div>{/* /.assign-grid */}
          </form>
        </div>
      </div>
    </div>
  );
}

function Label({ children }: { children: React.ReactNode }) {
  return (
    <span
      style={{
        fontSize: 11,
        fontWeight: 700,
        color: "var(--muted)",
        textTransform: "uppercase",
        letterSpacing: "0.06em",
      }}
    >
      {children}
    </span>
  );
}

// Compact stat tile for the cockpit panel — used to show stock
// pending count + free / carving / down counts inline.
function CockpitStat({ label, value, fg }: { label: string; value: number; fg: string }) {
  return (
    <div
      style={{
        padding: "8px 12px",
        background: "var(--surface)",
        border: "1px solid var(--border)",
        borderRadius: 8,
        textAlign: "center",
      }}
    >
      <div
        style={{
          fontSize: 9,
          color: "var(--muted)",
          textTransform: "uppercase",
          letterSpacing: "0.06em",
          fontWeight: 700,
        }}
      >
        {label}
      </div>
      <div
        style={{
          fontSize: 22,
          fontWeight: 800,
          color: fg,
          fontFamily: "ui-monospace, monospace",
          marginTop: 2,
        }}
      >
        {value}
      </div>
    </div>
  );
}

// Section header that visually partitions CNC and Manual vendors in
// the picker. The Manual header uses an amber accent + thin top-rule
// so the divide between the two vendor types is unmistakable.
function SectionHeader({
  label,
  hint,
  accent,
  topMargin,
}: {
  label: string;
  hint?: string;
  accent?: string;
  topMargin?: number;
}) {
  return (
    <div
      style={{
        display: "flex",
        alignItems: "baseline",
        gap: 8,
        marginTop: topMargin ?? 0,
        paddingTop: topMargin && topMargin > 0 ? 10 : 0,
        borderTop: topMargin && topMargin > 0 ? "1px dashed var(--border)" : "none",
      }}
    >
      <span
        style={{
          fontSize: 11,
          fontWeight: 800,
          letterSpacing: "0.07em",
          color: accent ?? "var(--gold-dark)",
          textTransform: "uppercase",
        }}
      >
        {label}
      </span>
      {hint && (
        <span style={{ fontSize: 10, color: "var(--muted-light)" }}>{hint}</span>
      )}
    </div>
  );
}
